import openpyxl

wb = openpyxl.load_workbook('input.xlsx')

# Create Sheet1 or use existing
if 'Sheet1' not in wb.sheetnames:
    ws_out = wb.create_sheet('Sheet1')
else:
    ws_out = wb['Sheet1']

ws_src = wb['denomination']

# Copy source data to Sheet1 if different
if ws_out != ws_src:
    for row in ws_src.iter_rows(min_row=1, max_row=ws_src.max_row, max_col=ws_src.max_column, values_only=False):
        for cell in row:
            ws_out.cell(cell.row, cell.column, cell.value)

# Denomination columns: H=1000, I=500, J=200, K=100, L=50, M=20, N=10, O=5, P=1
denoms = [1000, 500, 200, 100, 50, 20, 10, 5, 1]
col_map = {1000: 8, 500: 9, 200: 10, 100: 11, 50: 12, 20: 13, 10: 14, 5: 15, 1: 16}

employees = [(2, 5000), (3, 7000), (4, 2938), (5, 4558), (6, 35000), (7, 2700), (8, 32584)]
counts = {1000: 87, 500: 0, 200: 11, 100: 4, 50: 2, 20: 2, 10: 2, 5: 2, 1: 10}

# Greedy allocation (sorted by salary desc)
allocation = {}
remaining = dict(counts)
emp_sorted = sorted(employees, key=lambda x: -x[1])

for row, salary in emp_sorted:
    allocation[row] = {}
    left = salary
    for d in denoms:
        if remaining[d] > 0 and left >= d:
            use = min(left // d, remaining[d])
            allocation[row][d] = use
            remaining[d] -= use
            left -= use * d
        else:
            allocation[row][d] = 0

# Write to H2:P8
for row, salary in employees:
    for d in denoms:
        col = col_map[d]
        val = allocation[row].get(d, 0)
        ws_out.cell(row, col, val)

wb.save('output.xlsx')
print("Saved output.xlsx")
PYEOF
